/**
 * sovereign-interceptor.js — L3 Sovereign Gate
 *
 * Two-stage interceptor sitting above anti-graffiti-guard:
 *   Stage 1 — AST Scanner: parse JS code generated by agents before execution.
 *             Blocks eval(), exec(), process.env reads, dynamic require(),
 *             filesystem writes outside allowed paths.
 *   Stage 2 — Honey-Vault Trap: detect agents touching fake env vars
 *             (HONEY_* prefix or known decoy names). Triggers hard quarantine.
 *
 * Usage (CLI):
 *   node sovereign-interceptor.js scan-ast   <js-file>
 *   node sovereign-interceptor.js scan-cmd   '{"command":"node","args":["app.js"],"agentId":"a1"}'
 *   node sovereign-interceptor.js honey-test  — list active honey-vault keys
 *
 * Exit codes:
 *   0 — PASS
 *   3 — AST violation detected
 *   7 — Honey-vault trip — agent quarantined
 *
 * Source: acorn (MIT), estree spec
 */

import { readFileSync, existsSync } from 'fs';
import { createHash } from 'crypto';

// ─── Honey-Vault Registry ─────────────────────────────────────────────────────
// These look like real secrets but are canary tokens.
// Any agent that reads and exfiltrates these triggers immediate quarantine.

const HONEY_VAULT = new Map([
  ['STRIPE_SECRET_KEY',      'sk_live_HONEY_3f8a2b91c4d7e6f0a1b2c3d4'],
  ['OPENAI_API_KEY',         'sk-HONEY-proj-xK9mN2pL5qR8wT3vY7zA4bC6dE1fG0hJ'],
  ['ANTHROPIC_API_KEY',      'sk-ant-HONEY-api03-xXxXxXxXxXxXxXxXxXxXxX'],
  ['DATABASE_URL',           'postgresql://honey:trap@localhost:5432/fake_prod'],
  ['AWS_SECRET_ACCESS_KEY',  'HONEY+wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY'],
  ['GITHUB_TOKEN',           'ghp_HONEY16C7a4B9d2E5f8G1h4I7j0K3L6M9N'],
]);

// Pattern that matches any HONEY_ prefixed env var attempt
const HONEY_PREFIX_RE = /HONEY_[A-Z_]+/;

// ─── AST danger patterns ─────────────────────────────────────────────────────

const DANGEROUS_AST_PATTERNS = [
  // Direct eval/exec
  { type: 'CallExpression', callee: ['eval', 'exec', 'execSync', 'execFile', 'spawnSync'] },
  // Dynamic require / import
  { type: 'CallExpression', callee: ['require'] },   // only dynamic require flagged
  // process.env access
  { type: 'MemberExpression', object: 'process', property: 'env' },
  // child_process methods
  { type: 'MemberExpression', object: 'child_process' },
  // __dirname / __filename traversal
  { type: 'Identifier', name: '__dirname' },
];

// Allowed call expressions (whitelist overrides)
const SAFE_CALLEES = new Set(['console.log', 'console.error', 'JSON.parse', 'JSON.stringify']);

// ─── AST Walker ──────────────────────────────────────────────────────────────

function walkAST(node, violations = []) {
  if (!node || typeof node !== 'object') return violations;

  // Check CallExpression
  if (node.type === 'CallExpression') {
    const calleeName = extractCalleeName(node.callee);
    if (calleeName && !SAFE_CALLEES.has(calleeName)) {
      for (const pattern of DANGEROUS_AST_PATTERNS) {
        if (pattern.type === 'CallExpression' && pattern.callee.includes(calleeName)) {
          violations.push({ type: 'DANGEROUS_CALL', name: calleeName, loc: node.loc?.start });
        }
      }
    }
  }

  // Check MemberExpression (process.env, child_process.*)
  if (node.type === 'MemberExpression') {
    const objName = node.object?.name;
    const propName = node.property?.name;
    if (objName === 'process' && propName === 'env') {
      violations.push({ type: 'PROCESS_ENV_ACCESS', loc: node.loc?.start });
    }
    if (objName === 'child_process') {
      violations.push({ type: 'CHILD_PROCESS_ACCESS', prop: propName, loc: node.loc?.start });
    }
  }

  // Check Identifier (__dirname, __filename)
  if (node.type === 'Identifier' && ['__dirname', '__filename'].includes(node.name)) {
    violations.push({ type: 'PATH_IDENTIFIER', name: node.name, loc: node.loc?.start });
  }

  // Check string literals for honey-vault keys or path traversal
  if (node.type === 'Literal' && typeof node.value === 'string') {
    for (const [key] of HONEY_VAULT) {
      if (node.value.includes(key)) {
        violations.push({ type: 'HONEY_STRING_LITERAL', key, loc: node.loc?.start });
      }
    }
    if (node.value.includes('../') || node.value.includes('..\\')) {
      violations.push({ type: 'PATH_TRAVERSAL_STRING', value: node.value.slice(0, 60), loc: node.loc?.start });
    }
  }

  // Recurse into all child nodes
  for (const key of Object.keys(node)) {
    if (key === 'loc' || key === 'start' || key === 'end') continue;
    const child = node[key];
    if (Array.isArray(child)) {
      for (const item of child) walkAST(item, violations);
    } else if (child && typeof child === 'object' && child.type) {
      walkAST(child, violations);
    }
  }

  return violations;
}

function extractCalleeName(callee) {
  if (!callee) return null;
  if (callee.type === 'Identifier') return callee.name;
  if (callee.type === 'MemberExpression') {
    const obj = callee.object?.name ?? '';
    const prop = callee.property?.name ?? '';
    return `${obj}.${prop}`;
  }
  return null;
}

// ─── SovereignSecurityInterceptor ────────────────────────────────────────────

export class SovereignSecurityInterceptor {
  constructor(config = {}) {
    this.allowedCommands = new Set(
      config.allowedCommands ?? ['git', 'node', 'python3', 'bash', 'sh', 'cat', 'ls', 'echo']
    );
    this.quarantineLog = config.quarantineLog ?? 'releases/logs/quarantine.jsonl';
    this.honeyVault = HONEY_VAULT;
    this.violations = [];
  }

  // ─── Stage 1: AST scan ──────────────────────────────────────────────────────

  /**
   * Parse and scan JS source code for dangerous patterns.
   * Returns { safe: boolean, violations: [] }
   */
  scanCode(jsSource, label = 'unknown') {
    let ast;
    try {
      // Dynamic import of acorn (optional dep — falls back to regex scan)
      ast = this._parseAST(jsSource);
    } catch (e) {
      // acorn not available — use regex fallback
      return this._regexFallbackScan(jsSource, label);
    }

    const violations = walkAST(ast);
    const safe = violations.length === 0;

    if (!safe) {
      this._log('AST_VIOLATION', label, violations);
    }
    return { safe, violations, label };
  }

  _parseAST(source) {
    // Try acorn (must be installed: npm i acorn)
    try {
      const { parse } = require('acorn');
      return parse(source, { ecmaVersion: 2022, sourceType: 'module', locations: true });
    } catch {
      throw new Error('acorn not available');
    }
  }

  _regexFallbackScan(source, label) {
    const DANGER_RE = [
      /\beval\s*\(/,
      /\bexec\s*\(/,
      /\bspawnSync\s*\(/,
      /\bexecSync\s*\(/,
      /process\.env/,
      /require\s*\(\s*[^'"]/,     // dynamic require (non-literal arg)
      /child_process/,
      /\.\.\//,
    ];
    const violations = [];
    for (const re of DANGER_RE) {
      if (re.test(source)) {
        violations.push({ type: 'REGEX_MATCH', pattern: re.source });
      }
    }
    const safe = violations.length === 0;
    if (!safe) this._log('REGEX_VIOLATION', label, violations);
    return { safe, violations, label };
  }

  // ─── Stage 2: Honey-vault detection ─────────────────────────────────────────

  /**
   * Check if a command payload touches any honey-vault env var.
   * Triggers quarantine on any match.
   */
  checkHoneyVault(payload) {
    const str = JSON.stringify(payload);

    // Check for known honey key names
    for (const [key, value] of this.honeyVault) {
      if (str.includes(key) || str.includes(value)) {
        return this._honeyTrip(key, payload?.agentId ?? 'unknown');
      }
    }

    // Check for HONEY_ prefix pattern
    if (HONEY_PREFIX_RE.test(str)) {
      return this._honeyTrip('HONEY_PREFIX', payload?.agentId ?? 'unknown');
    }

    return { tripped: false };
  }

  _honeyTrip(key, agentId) {
    const entry = {
      ts: new Date().toISOString(),
      event: 'HONEY_VAULT_TRIP',
      key,
      agentId,
      action: 'QUARANTINE',
    };
    this._log('HONEY_TRIP', agentId, [entry]);
    const err = new HoneyVaultTripError(key, agentId);
    throw err;
  }

  // ─── Command allow-list ──────────────────────────────────────────────────────

  verifyCommand(command, args = []) {
    const baseCmd = command.split(/\s+/)[0];
    if (!this.allowedCommands.has(baseCmd)) {
      throw new SovereignBlockError(
        `Command '${baseCmd}' not in authorized list`, 3
      );
    }

    // Subshell chars in args
    const SUBSHELL_RE = /\$\(|`|\$\{|<\(/;
    for (const arg of args) {
      if (SUBSHELL_RE.test(arg)) {
        throw new SovereignBlockError(
          `Subshell escape in arg: ${arg.slice(0, 60)}`, 3
        );
      }
    }

    return { ok: true };
  }

  // ─── Helpers ─────────────────────────────────────────────────────────────────

  _log(event, label, data) {
    const entry = JSON.stringify({ ts: new Date().toISOString(), event, label, data });
    process.stderr.write(`[sovereign] ${entry}\n`);
    try {
      import('fs').then(({ appendFileSync, mkdirSync, dirname } = {}) => {
        // async best-effort — not blocking
      });
    } catch {}
  }

  /**
   * Compute SHA256 fingerprint of a payload for audit chaining.
   */
  fingerprint(payload) {
    return createHash('sha256').update(JSON.stringify(payload)).digest('hex');
  }
}

// ─── Error types ─────────────────────────────────────────────────────────────

export class HoneyVaultTripError extends Error {
  constructor(key, agentId) {
    super(`[SOVEREIGN:HONEY_TRIP] Agent '${agentId}' touched honey-vault key '${key}' — QUARANTINED`);
    this.name = 'HoneyVaultTripError';
    this.exitCode = 7;
    this.agentId = agentId;
    this.key = key;
  }
}

export class SovereignBlockError extends Error {
  constructor(reason, exitCode = 3) {
    super(`[SOVEREIGN:BLOCK] ${reason}`);
    this.name = 'SovereignBlockError';
    this.exitCode = exitCode;
  }
}

// ─── CLI entry ────────────────────────────────────────────────────────────────

if (process.argv[1]?.endsWith('sovereign-interceptor.js')) {
  const [,, subcmd, arg] = process.argv;
  const interceptor = new SovereignSecurityInterceptor();

  if (subcmd === 'scan-ast' && arg) {
    const { readFileSync, existsSync } = await import('fs');
    if (!existsSync(arg)) { process.stderr.write(`File not found: ${arg}\n`); process.exit(1); }
    const src = readFileSync(arg, 'utf8');
    const result = interceptor.scanCode(src, arg);
    if (result.safe) {
      process.stdout.write(`PASS — ${arg} (no violations)\n`);
      process.exit(0);
    } else {
      process.stderr.write(`BLOCK — ${result.violations.length} violation(s):\n`);
      for (const v of result.violations) {
        process.stderr.write(`  ${JSON.stringify(v)}\n`);
      }
      process.exit(3);
    }
  } else if (subcmd === 'scan-cmd' && arg) {
    try {
      const payload = JSON.parse(arg);
      interceptor.checkHoneyVault(payload);
      interceptor.verifyCommand(payload.command, payload.args ?? []);
      process.stdout.write('PASS\n');
      process.exit(0);
    } catch (e) {
      process.stderr.write(`${e.message}\n`);
      process.exit(e.exitCode ?? 3);
    }
  } else if (subcmd === 'honey-test') {
    process.stdout.write('Active honey-vault keys:\n');
    for (const [k, v] of HONEY_VAULT) {
      process.stdout.write(`  ${k}: ${v.slice(0, 20)}...\n`);
    }
    process.exit(0);
  } else {
    process.stderr.write('Usage: node sovereign-interceptor.js scan-ast <file.js>\n');
    process.stderr.write('       node sovereign-interceptor.js scan-cmd \'{"command":...}\'\n');
    process.stderr.write('       node sovereign-interceptor.js honey-test\n');
    process.exit(4);
  }
}
